from typing import List
class Solution:
    def solve(self, s: List[str]) -> str:
        result = ''
        for str in s:
            if str is not None:
                result += str
        return result

if __name__ == '__main__':
    solution = Solution()
    s = ['hello', None, 'world', 'python', None, 'DSA']
    print(solution.solve(s))

