#include <iostream>
#include <vector>
#include <string>
using namespace std;

class Solution {
public:
    string solve(vector<string>& s) {
        string result = '';
        for (string str : s) {
            if (!str.empty()) {
                result += str;
            }
        }
        return result;
    }
};

int main() {
    Solution solution;
    vector<string> s = {'hello', '', 'world', 'python', '', 'DSA'};
    cout << solution.solve(s);
    return 0;
}
